std::string run_test_cases() {
    std::stringstream ss_output;
    std::vector<Complex> complexes = {
        Complex(3, 4),
        Complex(5, -2),
        Complex(3, 0),
        Complex(0, 4),
        Complex(0, 0),
        Complex(3, 1),
        Complex(3, -1),
        Complex(0, 1),
        Complex(0, -1)
    };

    for (const auto& c : complexes) {
        ss_output << c << "\n";
    }
    return ss_output.str();
}

int main() {
    std::cout << run_test_cases();
    return 0;
}
